
-- 民用建筑设计统一标准条文表 V3.0
-- Table: civil_building_articles
DROP TABLE IF EXISTS civil_building_articles CASCADE;
DROP TABLE IF EXISTS civil_building_chapters CASCADE;

-- 章节表
CREATE TABLE civil_building_chapters (
    id SERIAL PRIMARY KEY,
    chapter_number VARCHAR(20) UNIQUE NOT NULL,
    chapter_title TEXT NOT NULL,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
    updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- 条文表
CREATE TABLE civil_building_articles (
    id SERIAL PRIMARY KEY,
    chapter_id INTEGER REFERENCES civil_building_chapters(id) ON DELETE CASCADE,
    article_number VARCHAR(50) UNIQUE NOT NULL,
    article_content TEXT NOT NULL,
    is_mandatory BOOLEAN DEFAULT FALSE,
    article_type VARCHAR(50),
    created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
    updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- 创建索引
CREATE INDEX idx_civil_articles_number ON civil_building_articles(article_number);
CREATE INDEX idx_civil_articles_mandatory ON civil_building_articles(is_mandatory);
CREATE INDEX idx_civil_articles_type ON civil_building_articles(article_type);
CREATE INDEX idx_civil_articles_chapter ON civil_building_articles(chapter_id);

-- 添加注释
COMMENT ON TABLE civil_building_chapters IS '规范章节表';
COMMENT ON TABLE civil_building_articles IS '规范条文表';
COMMENT ON COLUMN civil_building_articles.article_number IS '条文编号，如1.0.1';
COMMENT ON COLUMN civil_building_articles.article_content IS '条文内容';
COMMENT ON COLUMN civil_building_articles.is_mandatory IS '是否为强制性条文';
COMMENT ON COLUMN civil_building_articles.article_type IS '条文类型';


