((SELECT id FROM civil_building_chapters WHERE chapter_number = '2'), '2.0.8', '建筑控制线 building line 规划行政主管部门在道路红线、建设用地边界内。另行划定 的地面以上建(构)筑物主体不得超出的界线。', FALSE, '禁止性条文'),
((SELECT id FROM civil_building_chapters WHERE chapter_number = '2'), '2.0.9', '建筑密度 building density:building coverage ratio 在一定用地范围内,建筑物基底面积总和与总用地面积的比 率(%)。', FALSE, '一般性条文'),
((SELECT id FROM civil_building_chapters WHERE chapter_number = '2'), '2.0.10', '容积率 plot ratio: floor area ratio 在一定用地及计容范围内,建筑面积总和与用地面积的 比值。', FALSE, '一般性条文'),
((SELECT id FROM civil_building_chapters WHERE chapter_number = '2'), '2.0.11', '绿地率 greening rate 在一定用地范围内,各类绿地总面积占该用地总面积的比 率(%)。', FALSE, '一般性条文'),
((SELECT id FROM civil_building_chapters WHERE chapter_number = '2'), '2.0.12', '日照标准 insolation standard 根据建筑物所处的气候区、城市规模和建筑物的使用性质确 定的,在规定的日照标准日(冬至日或大寒日) 的有效日照时间 范围内。以有日照要求楼层的窗台面为计算起点的建筑外窗获得 的日照时间。', FALSE, '一般性条文'),
((SELECT id FROM civil_building_chapters WHERE chapter_number = '2'), '2.0.13', '层高 storey height 建筑物各层之间以楼、地面面层(完成面)计算的垂直距 离,屋顶层由该层楼面面层(完成面)至平屋面的结构面层或至 坡顶的结构面层与外墙外皮延长线的交点计算的垂直距离。', FALSE, '一般性条文'),
((SELECT id FROM civil_building_chapters WHERE chapter_number = '2'), '2.0.14', '室内净高 interior clear height 从楼、地面面层(完成面) 至吊顶或楼盖、屋盖底面之间的 有效使用空间的垂直距离。', FALSE, '一般性条文'),
((SELECT id FROM civil_building_chapters WHERE chapter_number = '2'), '2.0.15', '地下室 basement 房间地平面低于室外地平面的高度超过该房间净高的1 2者 为地下室。', FALSE, '一般性条文'),
((SELECT id FROM civil_building_chapters WHERE chapter_number = '2'), '2.0.16', '半地下室 semi-basement 房间地平面低于室外地平面的高度超过该房间净高的 1''3. 且不超过1/2者为半地下室。', FALSE, '一般性条文'),
((SELECT id FROM civil_building_chapters WHERE chapter_number = '2'), '2.0.17', '设备层 equipment floor 建筑物中专为设置暖通、空调、给水排水和电气等的设备和 管道H供人员进入操作用的空间层。', FALSE, '一般性条文'),
((SELECT id FROM civil_building_chapters WHERE chapter_number = '2'), '2.0.18', '避难层 refuge storey 在高度超过100.0m 的高层建筑中,用于人员在火灾时暂时 躲避火灾及其烟气危害的楼层。', FALSE, '一般性条文'),
((SELECT id FROM civil_building_chapters WHERE chapter_number = '2'), '2.0.19', '架空层 open floor 用结构支撑且无外围护墙体的开敞空间。', FALSE, '一般性条文'),
((SELECT id FROM civil_building_chapters WHERE chapter_number = '2'), '2.0.20', '台阶 step 连接室外或室内的不同标高的楼面、地面,供人行的阶梯式 交通道。', FALSE, '一般性条文'),
((SELECT id FROM civil_building_chapters WHERE chapter_number = '2'), '2.0.21', '临空高度 the vertical height between two open space 相邻开敞空间有高差时,上下楼地面之间的垂直距离。', FALSE, '一般性条文'),
((SELECT id FROM civil_building_chapters WHERE chapter_number = '2'), '2.0.22', '坡道 ramp 连接室外或室内的不同标高的楼面、地面,供人行或车行的 斜坡式交通道。', FALSE, '一般性条文'),
((SELECT id FROM civil_building_chapters WHERE chapter_number = '2'), '2.0.23', '栏杆 railing 具有一定的安全高度,用以保障人身安全或分隔空间用的防 护分隔构件。', FALSE, '一般性条文'),
((SELECT id FROM civil_building_chapters WHERE chapter_number = '2'), '2.0.24', '楼梯 stair 由连续行走的梯级、休息平台和维护安全的栏杆(或栏板)、 扶手以及相应的支承结构组成的作为楼层之间垂直交通用的建筑 部件。', FALSE, '一般性条文'),
((SELECT id FROM civil_building_chapters WHERE chapter_number = '2'), '2.0.25', '变形缝 deformation joint 为防止建筑物在外界因素作用下,结构内部产生附加变形和 应力, 导致建筑物开裂、碰撞甚至破坏而预留的构造缝、包括伸 缩缝、沉降缝和抗震缝。', FALSE, '一般性条文'),
((SELECT id FROM civil_building_chapters WHERE chapter_number = '2'), '2.0.26', '建筑幕墙 building curtain wall 由面板与支承结构体系(支承装置与支承结构) 组成的可相 对主体结构有一定位移能力或自身有一定变形能力、不承担主体 结构所受作用的建筑外围护墙。', FALSE, '一般性条文'),
((SELECT id FROM civil_building_chapters WHERE chapter_number = '2'), '2.0.27', '吊顶 suspended ceiling 悬吊在房屋屋顶或楼板结构下的顶棚。', FALSE, '一般性条文'),
((SELECT id FROM civil_building_chapters WHERE chapter_number = '2'), '2.0.28', '管道井pipe shaft 建筑物中用于布置坚向设备管线及设备的坚向井道。', FALSE, '一般性条文'),
((SELECT id FROM civil_building_chapters WHERE chapter_number = '2'), '2.0.29', '烟道 smoke uptake; smoke flue 排放各种烟气的管道、井道。', FALSE, '一般性条文'),
((SELECT id FROM civil_building_chapters WHERE chapter_number = '2'), '2.0.30', '通风道 air shaft 排除室内不良气体或者输送新鲜空气的管道、井道。', FALSE, '禁止性条文'),
((SELECT id FROM civil_building_chapters WHERE chapter_number = '2'), '2.0.31', '装修 decoration; finishing 以建筑物主体结构为依托,对建筑内、外空间进行的细部加 工和艺术处理。', FALSE, '一般性条文'),
((SELECT id FROM civil_building_chapters WHERE chapter_number = '2'), '2.0.32', '采光 daylighting 为保证人们生活、工作或生产活动具有适宜的光环境,使建 筑物内部使用空间取得的天然光照度满足使用、安全、舒适、美 观等要求的措施。', FALSE, '一般性条文'),
((SELECT id FROM civil_building_chapters WHERE chapter_number = '2'), '2.0.33', '采光系数 daylight factor 在室内给定平面上的一点,由直接或间接地接收来自假定和 已知天空亮度分布的天空漫射光而产生的照度与同一时刻该天空 半球在室外无遮挡水平面上产生的天空漫射光照度之比。', FALSE, '一般性条文'),
((SELECT id FROM civil_building_chapters WHERE chapter_number = '2'), '2.0.34', '采光系数标准值 standard value of daylight factor 在规定的室外天然光设计照度下,满足视觉功能要求时的采 光系数值。', FALSE, '一般性条文'),
((SELECT id FROM civil_building_chapters WHERE chapter_number = '2'), '2.0.35', '通风 ventilation 为保证人们生活、工作或生产活动具有适宜的空气环境,采 用自然或机械方法,对建筑物内部使用空间进行换气,使空气质 量满足卫生、安全、舒适等要求的技术。', FALSE, '一般性条文'),
((SELECT id FROM civil_building_chapters WHERE chapter_number = '2'), '2.0.36', '噪声 noise 影响人们正常生活、工作、学习、休息,甚至损害身心健康 的外界干扰声。', FALSE, '一般性条文'),
((SELECT id FROM civil_building_chapters WHERE chapter_number = '2'), '2.0.37', '建筑连接体 building connection 跨越道路红线、建设用地边界建造,连接不同用地之间地下 或地上的建筑物。', FALSE, '一般性条文'),
((SELECT id FROM civil_building_chapters WHERE chapter_number = '3'), '3.1.1', '民用建筑按使用功能可分为居住建筑和公共建筑两大类。 其中, 居住建筑可分为住宅建筑和宿舍建筑。', FALSE, '建议性条文'),
((SELECT id FROM civil_building_chapters WHERE chapter_number = '3'), '3.12', '民用建筑按地上建筑高度或层数进行分类应符合下列 规定: 1 建筑高度不大于27.0m 的住宅建筑、建筑高度不大于 21.0m 的公共建筑及建筑高度大于21.0m 的单层公共建筑为低 层或多层民用建筑; 2建筑高度大于27.0m 的住宅建筑和建筑高度大于24.0m 的非单层公共建筑,且高度不大于100.0m 的.为高层民用 建筑; 3 建筑高度大于100.0m 为超高层建筑。 注:建筑防火设计应符合现行国家标准《建筑设计防火规范》GB 50016有关建筑高度和层数计算的规定。', FALSE, '强制性条文'),
((SELECT id FROM civil_building_chapters WHERE chapter_number = '3'), '3.1.3', '民用建筑等级分类划分应符合国家现行有关标准或行业 主管部门的规定。', FALSE, '强制性条文'),
((SELECT id FROM civil_building_chapters WHERE chapter_number = '3'), '3.2', '设计使用年限', FALSE, '一般性条文'),
